mapper.select:
SELECT * FROM ( SELECT ROWNUM RNUM, ALL_LIST.* FROM ( SELECT X.USER_ID, X.USER_NM, X.USER_ABSNCE_AT, X.REG_YN, X.LAST_UPDUSR_ID, X.LAST_UPDT_PNTTM, X.FRST_REGIST_PNTTM FROM (SELECT A.USER_ID, A.USER_NM, (CASE WHEN B.USER_ABSNCE_AT IS NULL THEN 'N' ELSE B.USER_ABSNCE_AT END) AS USER_ABSNCE_AT, (CASE WHEN B.USER_ABSNCE_AT IS NULL THEN 'N' ELSE 'Y' END) AS REG_YN, B.LAST_UPDUSR_ID, TO_CHAR(B.LAST_UPDT_PNTTM,'YYYY-MM-DD') AS LAST_UPDT_PNTTM, TO_CHAR(B.FRST_REGIST_PNTTM,'YYYY-MM-DD') AS FRST_REGIST_PNTTM FROM COMVNUSERMASTER A LEFT OUTER JOIN COMTNUSERABSNCE B ON A.USER_ID = B.EMPLYR_ID ) X WHERE 1 = 1
AND X.USER_NM LIKE '%'||#{searchKeyword}||'%'
AND X.USER_ABSNCE_AT = #{selAbsnceAt}
ORDER BY LAST_UPDT_PNTTM DESC ) ALL_LIST ) Z WHERE RNUM > #{firstIndex} AND RNUM <= #{firstIndex} + #{recordCountPerPage}
